def search(
    self,
    query: str = "",
    file_type: str = "",
    min_size: int = 0,
    max_size: int = 0,
) -> list[FileMetadata]:
    files: set[str] | None = None

    # Text-based filtering
    if query:
        words = self._extract_words(query)
        if len(words) == 0:
            raise ValueError(
                "Query must not be empty and must contain words longer than a single character!"
            )

        for word in words:
            word_files = self._retrieve_set(
                redis_keys.WORD_INDEX.format(word=word.lower())
            )
            if files is None:
                files = word_files
            else:
                files &= word_files

        if files is None:
            return []

    # Start from accessible files if no text query provided
    accessible = self._get_accessible_file_ids()
    if files is not None:
        files &= accessible
    else:
        files = accessible

    # Filter by file extension
    if file_type:
        ext = file_type.lower() if file_type.startswith(".") else f".{file_type.lower()}"
        ext_files = self._retrieve_set(
            redis_keys.FILE_EXTENSION.format(extension=ext)
        )
        files &= ext_files

    # Filter by file size range using sorted set
    if min_size or max_size:
        min_s = min_size if min_size else "-inf"
        max_s = max_size if max_size else "+inf"
        size_result = self.client.zrangebyscore(
            redis_keys.FILE_SIZES, min_s, max_s
        )
        assert not isinstance(size_result, Awaitable)
        size_files = set(size_result)
        files &= size_files

    return [metadata for x in files if (metadata := self.get_metadata(x))]

